  rivalmon: "data:image/png;base64,",
  sparkvolt: "data:image/png;base64,",
  ampcore: "data:image/png;base64,",
  rustmoth: "data:image/png;base64,",
  slagmole: "data:image/png;base64,",
  forgeant: "data:image/png;base64,",
